def test_retry_happy_path_returns_value_first_attempt():
    calls = {"n": 0}

    def fn():
        calls["n"] += 1
        return "ok"

    assert retry(fn, max_attempts=3) == "ok"
    assert calls["n"] == 1


def test_retry_happy_path_succeeds_after_retries():
    calls = {"n": 0}

    def fn():
        calls["n"] += 1
        if calls["n"] < 3:
            raise ValueError("temporary failure")
        return "success"

    assert retry(fn, max_attempts=5) == "success"
    assert calls["n"] == 3  # fails twice, succeeds on 3rd attempt


def test_retry_error_when_always_fails_raises_last_exception():
    calls = {"n": 0}

    def fn():
        calls["n"] += 1
        raise RuntimeError("always failing")

    with pytest.raises(RuntimeError, match="always failing"):
        retry(fn, max_attempts=3)

    assert calls["n"] == 3  # exhausted all attempts


